import{_ as t,o,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"88. Fitness For Work","description":"","frontmatter":{"title":"88. Fitness For Work","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["ohs"]},"headers":[],"relativePath":"ebas/mspp/accident-pay-allowances/88-fitness-for-work.md","filePath":"ebas/mspp/accident-pay-allowances/88-fitness-for-work.md"}'),r={name:"ebas/mspp/accident-pay-allowances/88-fitness-for-work.md"};function n(i,e,p,l,h,m){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_88-fitness-for-work" tabindex="-1">88. Fitness For Work <a class="header-anchor" href="#_88-fitness-for-work" aria-label="Permalink to &quot;88. Fitness For Work&quot;">​</a></h1><p><strong>88.1</strong> Fit for Work</p><p><strong>a.</strong> The Employer is responsible for providing a workplace that is safe and without risk to health for Employees, so far as is reasonably practicable.</p><p><strong>b.</strong> Each Employee is responsible for ensuring that they are fit to perform their duties without risk to the safety, health and well-being of themselves and others within the workplace. This responsibility includes compliance with reasonable measures put in place by the Employer and any related occupational health and safety requirements.</p><p><strong>c.</strong> In the event the Employee’s manager forms a reasonable belief as defined at subclause 88.1d below that an Employee may be unfit to perform their duties, the manager will discuss their concerns with the Employee in a timely manner to promote physical, mental and emotional health so that Employees can safely undertake and sustain work.</p><p><strong>d.</strong> In this clause reasonable belief means a belief based on sufficient evidence that supports a conclusion on the balance of probabilities.</p><p><strong>e.</strong> In this clause treating medical practitioner may, where relevant, also include programs such as the Nursing and Midwifery Health Program Victoria, or a psychologist.</p><p><strong>f.</strong> The Employer will:</p><p><strong>(i)</strong> take all reasonable steps to give the Employee an opportunity to answer any concerns;</p><p><strong>(ii)</strong> recognise the Employee’s right to have a representative, including a Union representative, at any time when meeting with the Employer;</p><p><strong>(iii)</strong> genuinely consider the Employee’s response with a view to promoting physical, mental and emotional health so that Employees can safely undertake and sustain work; and</p><p><strong>(iv)</strong> take these responses into account in considering whether reasonable adjustments can be made in order that the Employee can safely undertake and sustain work.</p><p><strong>g.</strong> Where, after discussion with the Employee, the Employer continues to have a reasonable belief that the Employee is unfit to perform the duties, the Employer may request the Employee’s consent to obtain a report from the Employee’s treating medical practitioner regarding the Employee’s fitness for work. Where consent is given, the Employer will provide to the Employee, in writing, the concerns that form the basis of the reasonable belief to assist the Employee’s treating medical practitioner.</p><p><strong>h.</strong> Where the Employee attends a medical practitioner under subclause 88.1g above:</p><p><strong>(i)</strong> the Employee will provide a copy of the employer’s correspondence to the medical practitioner; and</p><p><strong>(ii)</strong> the Employer will pay for the cost of the appointment and any related report.</p><p><strong>i.</strong> The Employee will provide a copy of the report to the Employer.</p><p><strong>j.</strong> The Employer and Employee will meet to discuss any report.</p><p><strong>k.</strong> Nothing in this clause prevents an Employer from taking any reasonable step to ensure a safe work environment.</p><p><strong>88.2</strong> Reasonable Adjustments</p><p><strong>a.</strong> Where Employees have a disability (whether permanent or temporary) the Employer is required to make reasonable adjustments to enable the Employee to continue to perform their duties, subject to subclause 88.2b below.</p><p><strong>b.</strong> An Employer is not required to make reasonable adjustments if the Employee could not or cannot adequately perform the genuine and reasonable requirements of the employment even after the adjustments are made.</p><p>Plain language terms: fit for duty, medical assessment.</p>',23)])])}const y=t(r,[["render",n]]);export{d as __pageData,y as default};
